mapper.select:
SELECT u.*, d.dept_name, r.role_key, r.role_name FROM sys_user u LEFT JOIN sys_dept d ON u.dept_id = d.id LEFT JOIN sys_user_role ur ON u.id = ur.user_id LEFT JOIN sys_role r ON ur.role_id = r.id
AND u.username LIKE CONCAT('%', #{username}, '%')
AND u.status = #{status}
AND u.dept_id = #{deptId}
ORDER BY u.create_time DESC

mapper.update:
UPDATE sys_user
nickname = #{nickname}, email = #{email}, phone = #{phone}, avatar = #{avatar}, dept_id = #{deptId}, status = #{status}, password = #{password},
WHERE id = #{id}
